static int handle_get_notes(struct mg_connection* conn, void* cbdata) {
    char user_id_str[32];
    if (!get_param(conn, "user_id", user_id_str, sizeof(user_id_str))) {
        send_json(conn, 400, "Missing user_id", NULL);
        return 200;
    }

    int user_id = atoi(user_id_str);
    Note notes[100];
    int count = 0;
    db_note_get_by_user(user_id, notes, &count, 100);

    char data[32768];
    char* p = data;
    char* end = p + sizeof(data) - 1;
    *p++ = '[';
    for (int i = 0; i < count && p < end; i++) {
        if (i > 0) *p++ = ',';
        p += snprintf(p, end - p,
            "{\"id\":%d,\"title\":\"%s\",\"content\":\"%s\",\"created_at\":\"%s\"}",
            notes[i].id, notes[i].title, notes[i].content, notes[i].created_at);
    }
    *p++ = ']';
    *p = '\0';

    send_json(conn, 200, "OK", data);
    return 200;
}

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

int db_note_get_by_user(int user_id, Note* notes, int* count, int max_count) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, SELECT_NOTES_BY_USER, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    sqlite3_bind_int(stmt, 1, user_id);

    int i = 0;
    while (sqlite3_step(stmt) == SQLITE_ROW && i < max_count) {
        notes[i].id = sqlite3_column_int(stmt, 0);
        notes[i].user_id = sqlite3_column_int(stmt, 1);
        strncpy(notes[i].title, (const char*)sqlite3_column_text(stmt, 2), MAX_NOTE_TITLE_LEN - 1);

        if (sqlite3_column_text(stmt, 3)) {
            strncpy(notes[i].content, (const char*)sqlite3_column_text(stmt, 3), MAX_NOTE_CONTENT_LEN - 1);
        } else {
            notes[i].content[0] = '\0';
        }

        notes[i].is_deleted = sqlite3_column_int(stmt, 4);

        if (sqlite3_column_text(stmt, 5)) {
            strncpy(notes[i].created_at, (const char*)sqlite3_column_text(stmt, 5), 31);
        } else {
            notes[i].created_at[0] = '\0';
        }

        if (sqlite3_column_text(stmt, 6)) {
            strncpy(notes[i].updated_at, (const char*)sqlite3_column_text(stmt, 6), 31);
        } else {
            notes[i].updated_at[0] = '\0';
        }

        i++;
    }

    *count = i;
    sqlite3_finalize(stmt);
    return 0;
}

